// Assumed that there's a function to get the current date in this format: 'YYYY-MM-DD'
function getCurrentDate() {
    let today = new Date();
    let dd = String(today.getDate()).padStart(2, '0');
    let mm = String(today.getMonth() + 1).padStart(2, '0'); //January is 0!
    let yyyy = today.getFullYear();

    today = `${yyyy}-${mm}-${dd}`;
    return today;
}

function validateCouponCode(coupon) {
    if (!coupon) throw new Error('No coupon provided');
  
    let today = getCurrentDate();

    // Assuming `coupon.used_at` is the date when the coupon was last used, 
    // and we're assuming it follows 'YYYY-MM-DD' format
    if (coupon.used_at) throw new Error('Coupon has already been redeemed');
  
    // Assuming `coupon.expires_at` is the date when the coupon expires, 
    // and we're assuming it follows 'YYYY-MM<｜begin▁of▁sentence｜>-d' format
    if (today > coupon.expires_at) throw new Error('Coupon has expired');
  
    return true;
}